--- BtnTabList 控件 类

---@class UIBtnTabList
local UIBtnTabList = LxClass("UIBtnTabList", nil)

--- 列表
UIBtnTabList.TYPE_BTNLIST = 1

--- 按钮信息
UIBtnTabList.TYPE_BTNINFO = 2

function UIBtnTabList:UIBtnTabList()
    ---@type LWnd
    self._wndClass = nil

    self._tabScrollTrans = nil

    ---@type UIItemList
    self._uiList = nil

    self._dataList = {}

    --- 不改变的数据
    self._constDataList = {}

    self._curSel = nil

    --- 是否检查未开放的状态
    self._isCheckFuncShow = false

    self._type = UIBtnTabList.TYPE_BTNLIST

    --- self._type = UIBtnTabList.TYPE_BTNINFO
    self._btnList = {}
    self._btnTransList = {}
end

function UIBtnTabList:SetCheckLockFunc(func)
    self._checkLockCb = func
end
---@param wndClass LWnd
function UIBtnTabList:SetData(wndClass, tabScrollTrans, dataList, curSel, isCheckFuncShow, changeItemTextFunc)
    self._type = UIBtnTabList.TYPE_BTNLIST

    self._wndClass = wndClass
    self._tabScrollTrans = tabScrollTrans

    self._constDataList = dataList

    isCheckFuncShow = isCheckFuncShow and true or false
    self._isCheckFuncShow = isCheckFuncShow
    self._changeItemTextFunc = changeItemTextFunc
    if isCheckFuncShow then
        dataList = self:CheckIsFunctionShow(dataList)
    end

    self._dataList = dataList

    if not curSel and dataList and #dataList > 0 then
        curSel = dataList[1].btnType
    end

    self._curSel = curSel
    self:InitTabScroll(dataList)
    self:RefreshTabScroll()
end

function UIBtnTabList:CheckIsFunctionShow(dataList, isBtnInfo)
    local list = {}
    for i, v in ipairs(dataList) do
        local isIns = false
        if v.functionId and v.functionId > 0 then
            isIns = gModelFunctionOpen:CheckIsShow(v.functionId)
        else
            --- 没有功能开放id，不理
            isIns = true
        end
        if isBtnInfo then
            CS.ShowObject(v.btnTrans, isIns)
        end
        if isIns then
            table.insert(list, v)
        end
    end
    return list
end

function UIBtnTabList:SetCurSel(curSel)
    if not curSel then
        return
    end
    self._curSel = curSel
    self:RefreshTabScroll()
end

function UIBtnTabList:IsWndValid()
    if not self._wndClass or self._wndClass:IsDestroy() then
        return false
    end
    return true
end

function UIBtnTabList:RefreshTabScroll()
    if not self:IsWndValid() then
        return
    end
    if self._type == UIBtnTabList.TYPE_BTNLIST then
        self:_RefreshBtnList()
    elseif self._type == UIBtnTabList.TYPE_BTNINFO then
        self:_RefreshBtnInfo()
    end
end

function UIBtnTabList:RefreshTabRPState()
    if not self:IsWndValid() then
        return
    end

    if self._type ~= UIBtnTabList.TYPE_BTNINFO then
        return
    end

    local btnTransList = self._btnTransList
    for i, v in ipairs(self._btnList) do
        local btnTransInfo = btnTransList[v.btnType]
        if btnTransInfo then
            if v.checkRPFunc and btnTransInfo.redPoint then
                CS.ShowObject(btnTransInfo.redPoint, v.checkRPFunc())
            end
        end
    end
end

function UIBtnTabList:_RefreshBtnList()
    if not self._uiList then
        return
    end
    local list = self._dataList
    if self._isCheckFuncShow then
        list = self:CheckIsFunctionShow(self._constDataList)
        self._dataList = list
    end
    self._uiList:RefreshList(list)
end

function UIBtnTabList:_RefreshBtnInfo()
    if not self:IsWndValid() then
        return
    end

    self._btnList = self:CheckIsFunctionShow(self._constDataList, true)

    local wndClass = self._wndClass
    local btnTransList = self._btnTransList
    for i, v in ipairs(self._btnList) do
        local btnTransInfo = btnTransList[v.btnType]
        if btnTransInfo then
            local isSel = self:CheckIsSelTab(v)
            local status = isSel and 0 or 1
            wndClass:SetWndTabStatus(btnTransInfo.btnTrans, status)
            if v.checkRPFunc and btnTransInfo.redPoint then
                CS.ShowObject(btnTransInfo.redPoint, v.checkRPFunc())
            end
        end
    end
end

function UIBtnTabList:MoveToPos(index)
    if not self._uiList then
        return
    end
    if index and index > 0 then
        self._uiList:MoveToPos(index)
    end
end

function UIBtnTabList:InitTabScroll(dataList)
    if not self:IsWndValid() then
        return
    end
    local wndClass = self._wndClass
    local trans = self._tabScrollTrans
    local key = trans:GetInstanceID()
    local uiList = wndClass:GetUIScroll(key)
    self._uiList = uiList
    uiList:Create(trans, dataList, function(...)
        self:OnDrarwTabScrollItem(...)
    end)
end

function UIBtnTabList:OnDrarwTabScrollItem(list, item, itemdata, itempos)
    self:DisposeTabBtn(item, itemdata, itempos)
end

function UIBtnTabList:DisposeTabBtn(item, itemdata, itempos)
    if not self:IsWndValid() then
        return
    end

    local btnName = itemdata.btnName

    local wndClass = self._wndClass
    wndClass:SetWndTabText(item, btnName, itemdata.specialReduceSize)

    local isSel = self:CheckIsSelTab(itemdata)
    local status = isSel and 0 or 1
    wndClass:SetWndTabStatus(item, status)

    local offTrans = wndClass:FindWndTrans(item, "Off")
    if itemdata.offIcon then
        wndClass:SetWndEasyImage(offTrans, itemdata.offIcon, nil, itemdata.isNativeSize)
    end

    local onTrans = wndClass:FindWndTrans(item, "On")
    if itemdata.onIcon then
        wndClass:SetWndEasyImage(onTrans, itemdata.onIcon, nil, itemdata.isNativeSize)
    end

    local newStr, newTips
    local isOpen = true
    local LockTrans = wndClass:FindWndTrans(item, "Lock")
    local LockTxtTrans
    if LockTrans then
        LockTxtTrans = wndClass:FindWndTrans(LockTrans, "LockTxt")
        wndClass:SetWndText(LockTxtTrans, btnName)
        wndClass:InitTextLineWithLanguage(LockTxtTrans, -30)

        local functionId = itemdata.functionId
        if functionId and functionId > 0 then
            isOpen = gModelFunctionOpen:CheckIsOpened(functionId)
        else
            local _checkLockCb = self._checkLockCb
            if _checkLockCb ~= nil then
                isOpen, newStr, newTips = _checkLockCb(itemdata, itempos)
            end
        end
        CS.ShowObject(LockTrans, not isOpen)
    end

    if not isOpen then
        if not string.isempty(newStr) then
            wndClass:SetWndTabText(item, newStr)
        end
    end

    local redPoint = wndClass:FindWndTrans(item, "redPoint")
    if redPoint then
        local showRp = false
        local checkRPFunc = itemdata.checkRPFunc
        if checkRPFunc then
            showRp = checkRPFunc(itemdata)
        end
        CS.ShowObject(redPoint, showRp)
    end

    wndClass:SetWndClick(item, function()
        if not isOpen and not string.isempty(newTips) then
            GF.ShowMessage(newTips)
        else
            self:OnClickTabItem(itemdata, itempos)
        end
    end)

    if self._changeItemTextFunc then
        local offText = CS.FindTrans(offTrans, "Text")
        local onText = CS.FindTrans(onTrans, "Text")
        self._changeItemTextFunc(offText)
        self._changeItemTextFunc(onText)
    end

    return {
        btnTrans = item,
        offTrans = offTrans,
        onTrans = onTrans,
        LockTrans = LockTrans,
        LockTxtTrans = LockTxtTrans,
        redPoint = redPoint,
    }
end

function UIBtnTabList:CheckIsSelTab(itemData)
    return self._curSel == itemData.btnType
end

function UIBtnTabList:OnClickTabItem(itemdata, itempos)
    local functionId = itemdata.functionId
    if functionId and functionId > 0 then
        if not gModelFunctionOpen:CheckIsOpened(functionId, true) then
            return
        end
    else
        local _checkLockCb = self._checkLockCb
        if _checkLockCb ~= nil then
            local isOpen, newStr, newTips
            isOpen, newStr, newTips = _checkLockCb(itemdata, itempos)
            if not isOpen then
                if not string.isempty(newTips) then
                    GF.ShowMessage(newTips)
                end
                return
            end
        end
    end
    local clickFunc = itemdata.clickFunc
    if not clickFunc then
        return
    end

    local isClickSuc = clickFunc(itemdata)
    if isClickSuc == nil then
        isClickSuc = true
    end
    if not isClickSuc then
        return
    end

    self._curSel = itemdata.btnType
    self:RefreshTabScroll()
end

--- 传入的数据，需要比 SetData 多一个按钮节点，并且节点需要和 OnDrarwTabScrollItem 相同
function UIBtnTabList:SetBtnInfoData(wndClass, tabScrollTrans, btnList, curSel, isCheckFuncShow)
    self._type = UIBtnTabList.TYPE_BTNINFO

    self._wndClass = wndClass
    self._tabScrollTrans = tabScrollTrans

    btnList = btnList or {}
    self._constDataList = btnList

    if isCheckFuncShow then
        btnList = self:CheckIsFunctionShow(btnList, true)
    end

    self._btnList = btnList

    if not curSel and btnList and #btnList > 0 then
        curSel = btnList[1].btnType
    end
    self._curSel = curSel
    self:InitBtnTransList()
    self:RefreshTabScroll()
end

function UIBtnTabList:InitBtnTransList()
    self._btnTransList = {}

    if not self:IsWndValid() then
        return
    end

    local btnList = self._btnList
    if not btnList or #btnList < 1 then
        return
    end

    for i, v in ipairs(btnList) do
        self._btnTransList[v.btnType] = self:DisposeTabBtn(v.btnTrans, v, i)
    end
end

function UIBtnTabList:Destroy()
    if self:IsDestroy() then
        return
    end
    table.removeall(self)
    self._isDestroy = true
end

function UIBtnTabList:IsDestroy()
    return self._isDestroy
end

return UIBtnTabList